using System.ComponentModel.DataAnnotations;

namespace DocSummary.Models;

public class SummarizeRequest
{
    [Required]
    [MinLength(1)]
    public string Text { get; set; } = string.Empty;

    /// <summary>
    /// Maximum number of sentences in the summary (default: 3).
    /// </summary>
    [Range(1, 20)]
    public int MaxSentences { get; set; } = 3;
}

namespace DocSummary.Models;

public class SummarizeResponse
{
    public string Summary { get; set; } = string.Empty;
    public int OriginalSentenceCount { get; set; }
    public int SummarySentenceCount { get; set; }
}

namespace DocSummary.Services;

public interface IDocumentSummarizer
{
    /// <summary>
    /// Produces an extractive summary by selecting the most relevant sentences.
    /// </summary>
    (string Summary, int OriginalSentenceCount, int SummarySentenceCount) Summarize(string text, int maxSentences);
}

using System.Text.RegularExpressions;

namespace DocSummary.Services;

public partial class DocumentSummarizer : IDocumentSummarizer
{
    private static readonly HashSet<string> StopWords =
    [
        "a","an","the","and","or","but","is","are","was","were","be","been",
        "being","have","has","had","do","does","did","will","would","shall",
        "should","may","might","can","could","in","on","at","to","for","of",
        "with","by","from","as","into","about","between","through","after",
        "before","during","it","its","this","that","these","those","i","we",
        "you","he","she","they","me","him","her","us","them","my","our",
        "your","his","their","not","no","so","if","then","than","too","very",
        "just","also","more","most","such","each","every","all","any","both",
        "few","many","some","other","up","out","over","when","where","which",
        "while","who","whom","what","how"
    ];

    public (string Summary, int OriginalSentenceCount, int SummarySentenceCount) Summarize(string text, int maxSentences)
    {
        var sentences = SplitIntoSentences(text);

        if (sentences.Count <= maxSentences)
        {
            return (text.Trim(), sentences.Count, sentences.Count);
        }

        var wordFrequencies = ComputeWordFrequencies(sentences);
        var scored = ScoreSentences(sentences, wordFrequencies);

        // Pick the top-scoring sentences but preserve their original order.
        var topIndices = scored
            .OrderByDescending(s => s.Score)
            .Take(maxSentences)
            .Select(s => s.Index)
            .Order()
            .ToList();

        var summary = string.Join(" ", topIndices.Select(i => sentences[i].Trim()));

        return (summary, sentences.Count, topIndices.Count);
    }

    private static List<string> SplitIntoSentences(string text)
    {
        // Split on sentence-ending punctuation followed by whitespace or end-of-string.
        var parts = SentenceSplitter().Split(text.Trim());
        return parts.Where(s => !string.IsNullOrWhiteSpace(s)).ToList();
    }

    private static Dictionary<string, double> ComputeWordFrequencies(List<string> sentences)
    {
        var freq = new Dictionary<string, double>(StringComparer.OrdinalIgnoreCase);

        foreach (var sentence in sentences)
        {
            foreach (var word in ExtractWords(sentence))
            {
                if (StopWords.Contains(word)) continue;
                freq[word] = freq.GetValueOrDefault(word) + 1;
            }
        }

        // Normalise by the maximum frequency.
        if (freq.Count > 0)
        {
            var max = freq.Values.Max();
            foreach (var key in freq.Keys)
            {
                freq[key] /= max;
            }
        }

        return freq;
    }

    private static List<(int Index, double Score)> ScoreSentences(
        List<string> sentences,
        Dictionary<string, double> wordFrequencies)
    {
        var scored = new List<(int Index, double Score)>();

        for (var i = 0; i < sentences.Count; i++)
        {
            var words = ExtractWords(sentences[i]);
            var score = words
                .Where(w => !StopWords.Contains(w))
                .Sum(w => wordFrequencies.GetValueOrDefault(w));

            scored.Add((i, score));
        }

        return scored;
    }

    private static IEnumerable<string> ExtractWords(string text)
        => WordTokenizer().Matches(text).Select(m => m.Value.ToLowerInvariant());

    [GeneratedRegex(@"(?<=[.!?])\s+")]
    private static partial Regex SentenceSplitter();

    [GeneratedRegex(@"\b[a-zA-Z]+\b")]
    private static partial Regex WordTokenizer();
}

using DocSummary.Models;
using DocSummary.Services;
using Microsoft.AspNetCore.Mvc;

namespace DocSummary.Controllers;

[ApiController]
[Route("api/[controller]")]
public class SummarizeController(IDocumentSummarizer summarizer) : ControllerBase
{
    [HttpPost]
    public ActionResult<SummarizeResponse> Summarize([FromBody] SummarizeRequest request)
    {
        var (summary, originalCount, summaryCount) = summarizer.Summarize(request.Text, request.MaxSentences);

        return Ok(new SummarizeResponse
        {
            Summary = summary,
            OriginalSentenceCount = originalCount,
            SummarySentenceCount = summaryCount
        });
    }
}

